/* com.matjzing.mapper.FrontGroupsMapper.insertFrontGroups */
INSERT INTO TOPIC_MEMBER (
	  TOPIC_SEQ /**/
	, MEMBER_SEQ /**/
	, ROLE_TYPE /**/
	, JOIN_DT /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{topicSeq}
	, COALESCE(#{memberSeq}, #{registerSeq})
	, COALESCE(#{roleType}, 'PARTICIPANT')
	, NOW(3)
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

